<template>
    <div class="hz">
        <div class="aa">
            <button @click="jian">-</button>
            <span>{{ a }}</span>
            <button @click="jia">+</button>
        </div>
    </div>
</template>

<script>
import { ref } from 'vue'
export default {
    setup() {
        let a = ref(1)
        const jia = () => {
            if (a.value < 10) {
                a.value++
            } else {
                alert('不能再加了')
            }
        }
        const jian = () => {
            if (a.value > 0) {
                a.value--
            } else {
                alert('不能再减了')
            }
        }


        return {
            a,
            jia,
            jian
        }
    }
}
</script>

<style scoped>
.hz {
    width: 100%;
    height: 100%;
    background-color: #ccc;
}
.aa {
    /* width: 200px; */
    height: 100px;
    background-color: #fff;
    margin: 100px auto;
    text-align: center;

}

button {
    width: 100px;
    height: 50px;
    background-color: #ccc;
    border: none;
    outline: none;
    cursor: pointer;
}

span {
    width: 100px;
    height: 50px;
    line-height: 50px;
    text-align: center;
    display: inline-block;
    font-size: 20px;
}</style>